namespace sv_17cd039dfbfc431690b2b418fc442ddf.Services;

public class WarehouseInfo
{
    public string Id { get; set; } = "WH-001";
    public string Name { get; set; } = "Warehouse A";

    public static readonly IReadOnlyList<WarehouseInfo> Available =
    [
        new() { Id = "WH-001", Name = "Warehouse A" },
        new() { Id = "WH-002", Name = "Warehouse B" },
        new() { Id = "WH-003", Name = "Warehouse C" },
    ];
}

namespace sv_17cd039dfbfc431690b2b418fc442ddf.Services;

/// <summary>
/// Simulates a database query that returns the number of low-stock items
/// for a given warehouse.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16); // 0–15 inclusive
        return Task.FromResult(count);
    }
}

namespace sv_17cd039dfbfc431690b2b418fc442ddf.Services;

/// <summary>
