@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource

<div class="d-flex align-items-center">
    <label class="me-2 mb-0 text-nowrap"><strong>Warehouse:</strong></label>
    <select class="form-select form-select-sm" style="width: auto;"
            value="@_selectedId" @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseInfo.Available)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private string _selectedId = WarehouseInfo.Available[0].Id;

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? WarehouseInfo.Available[0].Id;
        var selected = WarehouseInfo.Available.First(w => w.Id == _selectedId);
        await WarehouseSource.NotifyChangedAsync(
            new WarehouseInfo { Id = selected.Id, Name = selected.Name });
    }
}

@rendermode InteractiveServer
@inject AlertState AlertState
@implements IDisposable

@if (AlertState.LowStockCount > 0)
{
    <span class="badge bg-danger ms-1">@AlertState.LowStockCount</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertState.OnChange += _handler;
    }

    public void Dispose() => AlertState.OnChange -= _handler;
}

@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@inject AlertState AlertState
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">
            📦 @Warehouse?.Name
        </h5>
        <p class="card-text">
            Low-stock items:
            @if (_loading)
            {
                <em>checking…</em>
            }
            else
            {
                <span class="badge bg-@(_alertCount > 0 ? "danger" : "success") fs-6">
                    @_alertCount
                </span>
            }
        </p>
        <p class="text-muted small mb-0">Refreshes every 10 seconds</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private int _alertCount;
    private bool _loading = true;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await PollNow();
            StartPolling();
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Warehouse changed — refresh immediately and restart polling.
        StopPolling();
        await PollNow();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = Task.Run(async () =>
        {
            try
            {
                while (await _timer.WaitForNextTickAsync(_cts.Token))
                {
                    await InvokeAsync(async () =>
                    {
                        await PollNow();
                        StateHasChanged();
                    });
                }
            }
            catch (OperationCanceledException) { }
        });
    }

    private async Task PollNow()
    {
        _loading = true;
        StateHasChanged();

        var warehouseId = Warehouse?.Id ?? WarehouseInfo.Available[0].Id;
        _alertCount = await AlertService.GetLowStockCountAsync(warehouseId);

        _loading = false;
        AlertState.SetCount(_alertCount);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose() => StopPolling();
}

