toolArgs.file_text:
@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@inject AlertState AlertState
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">
            📦 @Warehouse?.Name
        </h5>
        <p class="card-text">
            Low-stock items:
            @if (_loading)
            {
                <em>checking…</em>
            }
            else
            {
                <span class="badge bg-@(_alertCount > 0 ? "danger" : "success") fs-6">
                    @_alertCount
                </span>
            }
        </p>
        <p class="text-muted small mb-0">Refreshes every 10 seconds</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private int _alertCount;
    private bool _loading = true;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await PollNow();
            StartPolling();
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Warehouse changed — refresh immediately and restart polling.
        StopPolling();
        await PollNow();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = Task.Run(async () =>
        {
            try
            {
                while (await _timer.WaitForNextTickAsync(_cts.Token))
                {
                    await InvokeAsync(async () =>
                    {
                        await PollNow();
                        StateHasChanged();
                    });
                }
            }
            catch (OperationCanceledException) { }
        });
    }

    private async Task PollNow()
    {
        _loading = true;
        StateHasChanged();

        var warehouseId = Warehouse?.Id ?? WarehouseInfo.Available[0].Id;
        _alertCount = await AlertService.GetLowStockCountAsync(warehouseId);

        _loading = false;
        AlertState.SetCount(_alertCount);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose() => StopPolling();
}

