 using Microsoft.AspNetCore.Components;
 using sv_17cd039dfbfc431690b2b418fc442ddf.Components;
 using sv_17cd039dfbfc431690b2b418fc442ddf.Services;

 var builder = WebApplication.CreateBuilder(args);

 // Add services to the container.
 builder.Services.AddRazorComponents()
     .AddInteractiveServerComponents();

 // Warehouse state — CascadingValueSource crosses render mode boundaries
 // so the static layout's selector can communicate with interactive pages.
 builder.Services.AddCascadingValue(sp =>
 {
     var initial = new WarehouseInfo
     {
         Id = WarehouseInfo.Available[0].Id,
         Name = WarehouseInfo.Available[0].Name
     };
     return new CascadingValueSource<WarehouseInfo>(initial, isFixed: false);
 });

 // Scoped = per-circuit on Server, so each user gets independent state.
 builder.Services.AddScoped<InventoryAlertService>();
 builder.Services.AddScoped<AlertState>();

 var app = builder.Build();

 // Configure the HTTP request pipeline.
 if (!app.Environment.IsDevelopment())
 {
     app.UseExceptionHandler("/Error", createScopeForErrors: true);
 }
 app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
 app.UseAntiforgery();

 app.MapStaticAssets();
 app.MapRazorComponents<App>()
     .AddInteractiveServerRenderMode();

 app.Run();
